import { useState } from 'react';
import Bebidas from '../bebidas/bebidas';
import Burguers from '../burguers/burguers';
import Combos from '../combos/combos';
import './productos.css';


function Productos() {
    const [carrito, setCarrito] = useState([])

    const agregarCarrito = (e) => {
      console.log(e.targer.value)
    }

    return (
        <div className='cont-prod-mayor'>
            <h2>PRODUCTOS</h2>
            <Combos agregarCarrito={agregarCarrito} carrito={carrito} />
            <Burguers agregarCarrito={agregarCarrito} carrito={carrito} />
            <Bebidas agregarCarrito={agregarCarrito} carrito={carrito} />
        </div>
    )
}

export default Productos;
